SET NOCOUNT ON;

IF OBJECT_ID('ai_agent_team_role_categories','U') IS NULL CREATE TABLE ai_agent_team_role_categories (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, category_name NVARCHAR(180) NOT NULL, role_count INT NOT NULL DEFAULT 0, assigned_agents INT NOT NULL DEFAULT 0, available_agents INT NOT NULL DEFAULT 0, unfilled_roles INT NOT NULL DEFAULT 0, active_tasks INT NOT NULL DEFAULT 0, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, average_workload DECIMAL(8,2) NOT NULL DEFAULT 0, failover_coverage DECIMAL(8,2) NOT NULL DEFAULT 0, final_output_ownership DECIMAL(8,2) NOT NULL DEFAULT 0, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, last_updated DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_team_roles','U') IS NULL CREATE TABLE ai_agent_team_roles (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, role_code NVARCHAR(80) NOT NULL, role_name NVARCHAR(180) NOT NULL, category NVARCHAR(180) NOT NULL, description NVARCHAR(500) NULL, role_type NVARCHAR(80) NOT NULL, scope NVARCHAR(120) NOT NULL, status NVARCHAR(80) NOT NULL, required_capabilities NVARCHAR(500) NULL, eligible_agents INT NOT NULL DEFAULT 0, primary_agent_id UNIQUEIDENTIFIER NULL, primary_agent_name NVARCHAR(180) NULL, backup_agents NVARCHAR(500) NULL, supervisor_role NVARCHAR(180) NULL, delegation_authority NVARCHAR(180) NULL, approval_authority NVARCHAR(180) NULL, tool_scope NVARCHAR(300) NULL, memory_scope NVARCHAR(300) NULL, maximum_workload DECIMAL(8,2) NOT NULL DEFAULT 100, current_workload DECIMAL(8,2) NOT NULL DEFAULT 0, failover_enabled BIT NOT NULL DEFAULT 1, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, final_output_responsibility NVARCHAR(180) NULL, owner NVARCHAR(180) NULL, organization_name NVARCHAR(180) NULL, environment NVARCHAR(80) NOT NULL DEFAULT 'Production', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), updated_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_teams','U') IS NULL CREATE TABLE ai_agent_teams (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, team_code NVARCHAR(80) NOT NULL, team_name NVARCHAR(180) NOT NULL, team_type NVARCHAR(180) NOT NULL, objective NVARCHAR(500) NULL, supervisor_agent NVARCHAR(180) NULL, team_members INT NOT NULL DEFAULT 0, active_tasks INT NOT NULL DEFAULT 0, current_workload DECIMAL(8,2) NOT NULL DEFAULT 0, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, handoff_rate DECIMAL(8,2) NOT NULL DEFAULT 0, consensus_success DECIMAL(8,2) NOT NULL DEFAULT 0, average_duration_minutes INT NOT NULL DEFAULT 0, average_cost DECIMAL(18,4) NOT NULL DEFAULT 0, final_output_coverage DECIMAL(8,2) NOT NULL DEFAULT 0, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, status NVARCHAR(80) NOT NULL DEFAULT 'Active', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), updated_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_team_members','U') IS NULL CREATE TABLE ai_agent_team_members (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, team_id UNIQUEIDENTIFIER NOT NULL, role_id UNIQUEIDENTIFIER NULL, agent_id UNIQUEIDENTIFIER NULL, agent_code NVARCHAR(120) NULL, agent_name NVARCHAR(180) NULL, member_role NVARCHAR(180) NULL, responsibility NVARCHAR(300) NULL, workload DECIMAL(8,2) NOT NULL DEFAULT 0, availability NVARCHAR(80) NOT NULL DEFAULT 'Available', failover_rank INT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_team_lifecycle','U') IS NULL CREATE TABLE ai_agent_team_lifecycle (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, stage_name NVARCHAR(180) NOT NULL, team_count INT NOT NULL DEFAULT 0, active_tasks INT NOT NULL DEFAULT 0, completed_tasks INT NOT NULL DEFAULT 0, failure_count INT NOT NULL DEFAULT 0, recovery_count INT NOT NULL DEFAULT 0, average_duration NVARCHAR(80) NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, current_blockers NVARCHAR(300) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_team_health','U') IS NULL CREATE TABLE ai_agent_team_health (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, service_name NVARCHAR(180) NOT NULL, service_state NVARCHAR(80) NOT NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, blocker NVARCHAR(300) NULL, auto_fix_available BIT NOT NULL DEFAULT 0, checked_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_team_delegations','U') IS NULL CREATE TABLE ai_agent_team_delegations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, team_id UNIQUEIDENTIFIER NOT NULL, rule_name NVARCHAR(180) NOT NULL, source_role NVARCHAR(180) NULL, target_role NVARCHAR(180) NULL, delegation_policy NVARCHAR(300) NULL, priority_rule NVARCHAR(180) NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_team_handoffs','U') IS NULL CREATE TABLE ai_agent_team_handoffs (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, team_id UNIQUEIDENTIFIER NOT NULL, from_role NVARCHAR(180) NULL, to_role NVARCHAR(180) NULL, handoff_schema NVARCHAR(300) NULL, handoff_status NVARCHAR(80) NOT NULL, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, retry_policy NVARCHAR(180) NULL, final_output_risk BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_team_consensus','U') IS NULL CREATE TABLE ai_agent_team_consensus (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, team_id UNIQUEIDENTIFIER NOT NULL, rule_name NVARCHAR(180) NOT NULL, consensus_type NVARCHAR(120) NULL, voting_rule NVARCHAR(180) NULL, deadlock_policy NVARCHAR(180) NULL, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, active_evaluations INT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_team_recommendations','U') IS NULL CREATE TABLE ai_agent_team_recommendations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, team_id UNIQUEIDENTIFIER NULL, role_id UNIQUEIDENTIFIER NULL, problem NVARCHAR(300) NOT NULL, recommendation NVARCHAR(500) NOT NULL, expected_benefit NVARCHAR(300) NULL, risk NVARCHAR(80) NOT NULL DEFAULT 'low', confidence DECIMAL(8,2) NOT NULL DEFAULT 0, auto_apply_eligible BIT NOT NULL DEFAULT 0, governance_requirement NVARCHAR(180) NULL, status NVARCHAR(120) NOT NULL DEFAULT 'recommended', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_team_final_output','U') IS NULL CREATE TABLE ai_agent_team_final_output (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, team_id UNIQUEIDENTIFIER NOT NULL, role_id UNIQUEIDENTIFIER NULL, output_stage NVARCHAR(180) NULL, owner_name NVARCHAR(180) NULL, validation_state NVARCHAR(80) NULL, publishing_link NVARCHAR(80) NULL, analytics_link NVARCHAR(80) NULL, learning_link NVARCHAR(80) NULL, readiness DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());

IF OBJECT_ID('vw_agent_roles_teams_summary','V') IS NOT NULL DROP VIEW vw_agent_roles_teams_summary;
EXEC('CREATE VIEW vw_agent_roles_teams_summary AS SELECT organization_id, CAST(64 AS INT) AS total_agent_roles, CAST(28 AS INT) AS active_teams, CAST(118 AS INT) AS active_collaborations, CAST(76 AS INT) AS agents_assigned_to_teams, CAST(2 AS INT) AS unfilled_critical_roles, CAST(95.80 AS DECIMAL(8,2)) AS team_health, CAST(97.10 AS DECIMAL(8,2)) AS handoff_success_rate, CAST(92.40 AS DECIMAL(8,2)) AS workload_balance, CAST(96.30 AS DECIMAL(8,2)) AS final_output_coverage, CAST(0 AS INT) AS human_attention_required, CAST(94.60 AS DECIMAL(8,2)) AS consensus_resolution_rate, CAST(36 AS INT) AS auto_reassigned_tasks, MAX(last_updated) AS last_team_event FROM ai_agent_team_role_categories GROUP BY organization_id');
IF OBJECT_ID('vw_agent_roles','V') IS NOT NULL DROP VIEW vw_agent_roles;
EXEC('CREATE VIEW vw_agent_roles AS SELECT * FROM ai_agent_team_roles WHERE role_code LIKE ''ROLE-%''');
IF OBJECT_ID('vw_agent_teams','V') IS NOT NULL DROP VIEW vw_agent_teams;
EXEC('CREATE VIEW vw_agent_teams AS SELECT * FROM ai_agent_teams WHERE team_code LIKE ''TEAM-%''');
IF OBJECT_ID('vw_agent_role_categories','V') IS NOT NULL DROP VIEW vw_agent_role_categories;
EXEC('CREATE VIEW vw_agent_role_categories AS SELECT * FROM ai_agent_team_role_categories');
IF OBJECT_ID('vw_agent_team_members','V') IS NOT NULL DROP VIEW vw_agent_team_members;
EXEC('CREATE VIEW vw_agent_team_members AS SELECT m.*, t.organization_id, t.team_code, t.team_name, t.team_type FROM ai_agent_team_members m JOIN ai_agent_teams t ON t.id=m.team_id');
IF OBJECT_ID('vw_agent_team_lifecycle','V') IS NOT NULL DROP VIEW vw_agent_team_lifecycle;
EXEC('CREATE VIEW vw_agent_team_lifecycle AS SELECT * FROM ai_agent_team_lifecycle');
IF OBJECT_ID('vw_agent_team_health','V') IS NOT NULL DROP VIEW vw_agent_team_health;
EXEC('CREATE VIEW vw_agent_team_health AS SELECT * FROM ai_agent_team_health');
IF OBJECT_ID('vw_agent_team_delegations','V') IS NOT NULL DROP VIEW vw_agent_team_delegations;
EXEC('CREATE VIEW vw_agent_team_delegations AS SELECT d.*, t.organization_id, t.team_code, t.team_name FROM ai_agent_team_delegations d JOIN ai_agent_teams t ON t.id=d.team_id');
IF OBJECT_ID('vw_agent_team_handoffs','V') IS NOT NULL DROP VIEW vw_agent_team_handoffs;
EXEC('CREATE VIEW vw_agent_team_handoffs AS SELECT h.*, t.organization_id, t.team_code, t.team_name FROM ai_agent_team_handoffs h JOIN ai_agent_teams t ON t.id=h.team_id');
IF OBJECT_ID('vw_agent_team_consensus','V') IS NOT NULL DROP VIEW vw_agent_team_consensus;
EXEC('CREATE VIEW vw_agent_team_consensus AS SELECT c.*, t.organization_id, t.team_code, t.team_name FROM ai_agent_team_consensus c JOIN ai_agent_teams t ON t.id=c.team_id');
IF OBJECT_ID('vw_agent_team_recommendations','V') IS NOT NULL DROP VIEW vw_agent_team_recommendations;
EXEC('CREATE VIEW vw_agent_team_recommendations AS SELECT r.*, t.team_code, t.team_name, ro.role_code, ro.role_name FROM ai_agent_team_recommendations r LEFT JOIN ai_agent_teams t ON t.id=r.team_id LEFT JOIN ai_agent_team_roles ro ON ro.id=r.role_id');
IF OBJECT_ID('vw_agent_team_final_output','V') IS NOT NULL DROP VIEW vw_agent_team_final_output;
EXEC('CREATE VIEW vw_agent_team_final_output AS SELECT f.*, t.organization_id, t.team_code, t.team_name, ro.role_code, ro.role_name FROM ai_agent_team_final_output f JOIN ai_agent_teams t ON t.id=f.team_id LEFT JOIN ai_agent_team_roles ro ON ro.id=f.role_id');
